import{_ as n,H as a,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"一致性、共识、一致性模型","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/03-一致性、共识、一致性模型.md","filePath":"../distributedLearning/03-一致性、共识、一致性模型.md","lastUpdated":1778496697000}'),o={name:"../distributedLearning/03-一致性、共识、一致性模型.md"};function i(p,s,l,r,d,c){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="一致性、共识、一致性模型" tabindex="-1">一致性、共识、一致性模型 <a class="header-anchor" href="#一致性、共识、一致性模型" aria-label="Permalink to &quot;一致性、共识、一致性模型&quot;">​</a></h1><p>英文里 <strong>Consistency</strong>、<strong>Consensus</strong>、<strong>Consistency Model</strong> 是三个完全不同的概念,中文翻译都带&quot;一致&quot;两个字,<strong>于是从十多年前开始全行业混着用,新人入门时被术语硬生生绕晕</strong>。&quot;Kafka 是强一致&quot;、&quot;Raft 提供线性一致性&quot;、&quot;我们用 Paxos 实现一致性&quot;——这些句子里&quot;一致&quot;指的是同一件事吗?<strong>不是。混着用,选型和排错都会跑偏</strong>。这一篇专门把三个词分清,<strong>这一层的术语干净了,后续 16-19 篇一致性模型、09-15 篇共识算法,你才能直接读懂论文</strong>。</p><blockquote><p>一句话先记住:<strong>Consensus(共识)是手段、Consistency(一致性)是结果、Consistency Model(一致性模型)是契约</strong>。共识是&quot;N 个节点对一个值达成一致&quot;的算法(Paxos / Raft);一致性是&quot;多副本数据状态相同程度&quot;的工程描述(强 / 弱 / 最终);一致性模型是&quot;程序员视角的内存可见性契约&quot;(Linearizability / Sequential / Causal)。<strong>&quot;Kafka 是强一致&quot;是错的——它的 ISR 同步复制只能给你 monotonic reads,达不到 Linearizability</strong>——这个 confusion 后面会反复打你。</p></blockquote><hr><h2 id="一、为什么必须把三个词分开" tabindex="-1">一、为什么必须把三个词分开 <a class="header-anchor" href="#一、为什么必须把三个词分开" aria-label="Permalink to &quot;一、为什么必须把三个词分开&quot;">​</a></h2><p>先用一个生活类比理解为什么这三个词必须分开:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>共识 (Consensus) ── 像三个人投票决定&quot;今晚吃什么&quot;</span></span>
<span class="line"><span>                    ├─ 这是个&quot;算法/过程&quot;</span></span>
<span class="line"><span>                    └─ 解决&quot;怎么从分歧到一致&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>一致性 (Consistency) ── 像投票完成后&quot;三个人都知道吃火锅&quot;</span></span>
<span class="line"><span>                       ├─ 这是个&quot;结果/状态&quot;</span></span>
<span class="line"><span>                       └─ 描述&quot;多副本数据相同程度&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>一致性模型 (Consistency Model) ── 像规定&quot;投票时必须实时通知所有人&quot;</span></span>
<span class="line"><span>                                  ├─ 这是个&quot;契约/规约&quot;</span></span>
<span class="line"><span>                                  └─ 描述&quot;程序员看到什么样的内存视图&quot;</span></span></code></pre></div><p><strong>三个词回答的是三个不同问题</strong>:</p><table tabindex="0"><thead><tr><th>问题</th><th>答案</th><th>落到工程</th></tr></thead><tbody><tr><td>节点之间怎么达成同一个决定?</td><td>Consensus(共识算法)</td><td>Paxos / Raft / ZAB / PBFT</td></tr><tr><td>多个副本的数据有多接近?</td><td>Consistency(一致性程度)</td><td>强一致 / 弱一致 / 最终一致</td></tr><tr><td>并发读写时程序员能看到什么?</td><td>Consistency Model(一致性模型)</td><td>Linearizability / Causal / Eventual</td></tr></tbody></table><p>这三个<strong>不在同一层</strong>——共识算法是&quot;机制&quot;,它产出&quot;一致性这个结果&quot;,而程序员对外承诺&quot;一致性模型这个契约&quot;。<strong>混着用,就像把&quot;投票&quot;、&quot;投票结果&quot;、&quot;民主制度&quot;混着说一样</strong>。</p><hr><h2 id="二、consensus-共识-节点对一个值达成一致" tabindex="-1">二、Consensus(共识):节点对一个值达成一致 <a class="header-anchor" href="#二、consensus-共识-节点对一个值达成一致" aria-label="Permalink to &quot;二、Consensus(共识):节点对一个值达成一致&quot;">​</a></h2><p><strong>定义</strong>:<strong>N 个节点,通过一个算法,对单一个&quot;值&quot;达成一致</strong>——这个&quot;值&quot;可以是一个数字、一条日志条目、一个状态变更。</p><h3 id="_2-1-共识问题的标准形式" tabindex="-1">2.1 共识问题的标准形式 <a class="header-anchor" href="#_2-1-共识问题的标准形式" aria-label="Permalink to &quot;2.1 共识问题的标准形式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>N 个节点,每个节点可能 propose 一个值 v_i:</span></span>
<span class="line"><span>  N1 propose v_1</span></span>
<span class="line"><span>  N2 propose v_2</span></span>
<span class="line"><span>  N3 propose v_3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>共识算法必须保证:</span></span>
<span class="line"><span>  1. Termination(终止性):所有非故障节点最终决定一个值</span></span>
<span class="line"><span>  2. Validity(有效性):决定的值必须是某个节点提议过的</span></span>
<span class="line"><span>  3. Agreement(一致性):所有非故障节点决定相同的值</span></span></code></pre></div><p><strong>注意</strong>:<strong>&quot;所有非故障节点决定相同的值&quot;——这里的&quot;一致&quot;是 Agreement,不是&quot;一致性&quot;那个词</strong>。Agreement 是共识算法的目标属性,<strong>和 Consistency Model 里的&quot;一致&quot;是两层概念</strong>。</p><h3 id="_2-2-共识的经典算法" tabindex="-1">2.2 共识的经典算法 <a class="header-anchor" href="#_2-2-共识的经典算法" aria-label="Permalink to &quot;2.2 共识的经典算法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算法</th><th>故障模型</th><th>节点数</th><th>典型实现</th></tr></thead><tbody><tr><td>Basic Paxos</td><td>Crash-recovery</td><td>2f+1</td><td>几乎没有直接生产使用</td></tr><tr><td>Multi-Paxos</td><td>Crash-recovery</td><td>2f+1</td><td>Google Chubby、Spanner</td></tr><tr><td>Raft</td><td>Crash-recovery</td><td>2f+1</td><td>etcd、Consul、TiKV、CockroachDB</td></tr><tr><td>ZAB</td><td>Crash-recovery</td><td>2f+1</td><td>ZooKeeper</td></tr><tr><td>EPaxos</td><td>Crash-recovery</td><td>2f+1</td><td>实验性,无 Leader Paxos</td></tr><tr><td>PBFT</td><td>Byzantine</td><td>3f+1</td><td>Hyperledger Fabric、联盟链</td></tr><tr><td>HotStuff</td><td>Byzantine</td><td>3f+1</td><td>Diem(原 Libra)、Aptos</td></tr><tr><td>PoW</td><td>Byzantine + 匿名身份</td><td>算力多数</td><td>Bitcoin</td></tr></tbody></table><p><strong>共识算法做的事就一件</strong>:<strong>让 N 个节点在面对故障、网络分区、并发提议的情况下,对某个&quot;值&quot;达成一致</strong>。<strong>它不直接提供一致性模型</strong>——一致性模型是建在共识之上的应用层契约。</p><h3 id="_2-3-共识-复制" tabindex="-1">2.3 共识 ≠ 复制 <a class="header-anchor" href="#_2-3-共识-复制" aria-label="Permalink to &quot;2.3 共识 ≠ 复制&quot;">​</a></h3><p>很多人把&quot;复制&quot;和&quot;共识&quot;画等号——<strong>不对</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>复制 (Replication):一份数据在多台机器上有副本</span></span>
<span class="line"><span>                  └─ 复制可以异步、可以丢、可以延迟</span></span>
<span class="line"><span>                  └─ MySQL 主从就是复制,没有共识</span></span>
<span class="line"><span></span></span>
<span class="line"><span>共识 (Consensus):多个节点对&quot;值&quot;达成一致(强一致的决定)</span></span>
<span class="line"><span>                └─ 共识协议保证 Agreement,即所有正确节点决定同一个值</span></span>
<span class="line"><span>                └─ Raft / Paxos 是复制 + 共识</span></span></code></pre></div><blockquote><p><strong>共识是&quot;强复制&quot;——它保证多副本看到的写顺序完全一致</strong>。一般的异步复制可以&quot;先写完主再传给从&quot;,从机滞后几秒;<strong>共识协议要求&quot;多数派同步确认才算写完&quot;</strong>,这是它的代价(延迟高),也是它的价值(强一致)。</p></blockquote><h3 id="_2-4-共识协议解决的不变量" tabindex="-1">2.4 共识协议解决的不变量 <a class="header-anchor" href="#_2-4-共识协议解决的不变量" aria-label="Permalink to &quot;2.4 共识协议解决的不变量&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>共识协议给你的不变量:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. 决定唯一:对任何提议序列,所有正确节点决定同样的值</span></span>
<span class="line"><span>  2. 决定不变:一旦决定就不会改(safety)</span></span>
<span class="line"><span>  3. 决定可达:多数派活着就一定能决定(liveness,在 partial sync 下)</span></span></code></pre></div><p><strong>这三个不变量是建一切分布式系统的基石</strong>——分布式锁(必须达成&quot;谁持有锁&quot;的共识)、选主(必须达成&quot;谁是 Leader&quot;的共识)、状态机复制(必须达成&quot;日志顺序&quot;的共识)。<strong>所有 etcd / ZK / Consul / TiKV 提供的服务,底层都是共识协议的应用</strong>。</p><hr><h2 id="三、consistency-一致性-多副本的数据相同程度" tabindex="-1">三、Consistency(一致性):多副本的数据相同程度 <a class="header-anchor" href="#三、consistency-一致性-多副本的数据相同程度" aria-label="Permalink to &quot;三、Consistency(一致性):多副本的数据相同程度&quot;">​</a></h2><p><strong>定义</strong>:<strong>多副本数据在某一时刻&quot;有多接近&quot;</strong>——通俗讲就是&quot;主写完了,从什么时候能看到&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强一致 (Strong) ────────────────────────── 弱一致 (Weak)</span></span>
<span class="line"><span>   │                                          │</span></span>
<span class="line"><span>   主写完瞬间从就能看到                    主写完后过一会从才能看到</span></span>
<span class="line"><span>   读永远拿到最新值                         读可能拿到旧值</span></span>
<span class="line"><span>   实现成本高                              实现成本低</span></span></code></pre></div><h3 id="_3-1-一致性的程度" tabindex="-1">3.1 一致性的程度 <a class="header-anchor" href="#_3-1-一致性的程度" aria-label="Permalink to &quot;3.1 一致性的程度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>级别</th><th>描述</th><th>典型实现</th></tr></thead><tbody><tr><td>Strong</td><td>写完瞬间所有副本可见</td><td>同步复制 + 共识协议</td></tr><tr><td>Eventual</td><td>给足够时间,最终所有副本一致</td><td>异步复制(MySQL 异步、Cassandra)</td></tr><tr><td>Weak</td><td>没有强保证,中间状态可见</td><td>缓存层、CRDT 的中间态</td></tr></tbody></table><p><strong>注意</strong>:<strong>这里说的&quot;一致性&quot;是工程描述,不是严格的形式化定义</strong>——后面讲的&quot;一致性模型&quot;才是形式化的契约。<strong>这是行业常用语,但理论上 Consistency 的含义只有 ACID 里的 C(数据库约束完整性)和 Consistency Model 两种严格定义</strong>——下面用&quot;一致性程度&quot;避免混淆。</p><h3 id="_3-2-一致性程度-vs-共识" tabindex="-1">3.2 一致性程度 vs 共识 <a class="header-anchor" href="#_3-2-一致性程度-vs-共识" aria-label="Permalink to &quot;3.2 一致性程度 vs 共识&quot;">​</a></h3><p><strong>一致性程度是结果,共识是手段</strong>——但不是所有强一致都靠共识。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强一致达成的几种方式:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  方式 1:单机(没有多副本,自然强一致)</span></span>
<span class="line"><span>  方式 2:同步复制(主写完后等所有从确认再返回)</span></span>
<span class="line"><span>  方式 3:共识协议(Paxos / Raft,多数派同意)</span></span>
<span class="line"><span>  方式 4:分布式事务(2PC,所有参与者都提交)</span></span></code></pre></div><p><strong>MySQL 半同步复制就是&quot;同步复制&quot;达成的强一致</strong>——它没用共识协议。<strong>Raft 是&quot;共识协议&quot;达成的强一致</strong>——它用了 majority quorum。<strong>两者的故障表现不同</strong>:</p><ul><li>MySQL 半同步:主挂了 → 必须人为切换 → 期间不可用</li><li>Raft:Leader 挂了 → 集群自动选举新 Leader → 几秒钟恢复</li></ul><blockquote><p><strong>共识协议 = 同步复制 + 自动选主 + 故障容错</strong>——这是它比&quot;纯同步复制&quot;贵但更工程化的原因。</p></blockquote><h3 id="_3-3-acid-里的-c-是另一回事" tabindex="-1">3.3 ACID 里的 C 是另一回事 <a class="header-anchor" href="#_3-3-acid-里的-c-是另一回事" aria-label="Permalink to &quot;3.3 ACID 里的 C 是另一回事&quot;">​</a></h3><p><strong>数据库 ACID 里的 C(Consistency)指的是&quot;事务前后,数据满足应用层约束&quot;</strong>——比如&quot;账户余额不能负&quot;、&quot;外键约束&quot;、&quot;唯一索引&quot;。<strong>这和分布式的&quot;多副本一致性&quot;是完全不同的概念</strong>,只是英文都叫 Consistency。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACID 的 C:事务执行后,数据库依然满足业务约束</span></span>
<span class="line"><span>              └─ 应用层定义的不变量</span></span>
<span class="line"><span>              └─ 比如转账后 A.balance + B.balance 不变</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分布式的 C:多副本数据相同程度</span></span>
<span class="line"><span>              └─ 副本之间的对齐程度</span></span>
<span class="line"><span>              └─ 比如主写了 x=1,从能不能立刻看到 x=1</span></span></code></pre></div><p><strong>两者的混淆</strong>:很多教科书把 CAP 的 C 解释成 ACID 的 C——<strong>错</strong>。<strong>CAP 的 C 是 Linearizability</strong>(详见下一节),是分布式一致性模型的最强档,<strong>完全不是 ACID 的 C</strong>。</p><hr><h2 id="四、consistency-model-一致性模型-程序员看到的契约" tabindex="-1">四、Consistency Model(一致性模型):程序员看到的契约 <a class="header-anchor" href="#四、consistency-model-一致性模型-程序员看到的契约" aria-label="Permalink to &quot;四、Consistency Model(一致性模型):程序员看到的契约&quot;">​</a></h2><p><strong>这是最严格、最理论的概念</strong>——<strong>形式化定义&quot;并发读写下,程序员能看到什么样的内存视图&quot;</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一致性模型 (Consistency Model)</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ Linearizability   (线性一致性,最强)</span></span>
<span class="line"><span>   ├─ Sequential        (顺序一致性)</span></span>
<span class="line"><span>   ├─ Causal           (因果一致性)</span></span>
<span class="line"><span>   ├─ Read-Your-Writes (读自己写)</span></span>
<span class="line"><span>   ├─ Monotonic Reads  (单调读)</span></span>
<span class="line"><span>   ├─ Monotonic Writes (单调写)</span></span>
<span class="line"><span>   └─ Eventual         (最终一致,最弱)</span></span></code></pre></div><p><strong>一致性模型回答的问题是</strong>:<strong>&quot;程序员在多线程 / 多客户端并发访问时,会看到什么样的执行历史?&quot;</strong></p><h3 id="_4-1-linearizability-线性一致性-看起来像单机" tabindex="-1">4.1 Linearizability(线性一致性):看起来像单机 <a class="header-anchor" href="#_4-1-linearizability-线性一致性-看起来像单机" aria-label="Permalink to &quot;4.1 Linearizability(线性一致性):看起来像单机&quot;">​</a></h3><p>最强的一致性模型——<strong>所有操作看起来像在单机上原子地、按某个全局顺序执行</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>程序员视角:</span></span>
<span class="line"><span>  3 个客户端并发操作 → 看起来像</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>  把所有操作排成一个全局顺序,然后单机原子执行</span></span></code></pre></div><p><strong>关键性质</strong>:</p><ul><li><strong>每个操作有一个&quot;线性化点&quot;</strong>——在请求开始和返回之间</li><li><strong>如果操作 A 在操作 B 开始前完成,那么在全局顺序里 A 必须排在 B 前</strong>(real-time order)</li><li><strong>每个读必须返回最近一次写的值</strong>(在全局顺序里最近的)</li></ul><p><strong>典型实现</strong>:Raft / Paxos / 2PC——<strong>所有共识协议都给 Linearizability</strong>(配合正确的客户端逻辑)。</p><p><strong>代价</strong>:<strong>延迟高</strong>——每次写都要走多数派,跨地域延迟成百毫秒。</p><h3 id="_4-2-sequential-consistency-顺序一致性-像单机但不要求实时" tabindex="-1">4.2 Sequential Consistency(顺序一致性):像单机但不要求实时 <a class="header-anchor" href="#_4-2-sequential-consistency-顺序一致性-像单机但不要求实时" aria-label="Permalink to &quot;4.2 Sequential Consistency(顺序一致性):像单机但不要求实时&quot;">​</a></h3><p><strong>比 Linearizability 弱一档</strong>——同样要求全局顺序,<strong>但不要求和真实时间一致</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Linearizability:</span></span>
<span class="line"><span>  - 全局顺序 ✓</span></span>
<span class="line"><span>  - 必须符合&quot;操作完成时间&quot;的偏序(real-time)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sequential Consistency:</span></span>
<span class="line"><span>  - 全局顺序 ✓</span></span>
<span class="line"><span>  - 不要求和真实时间一致</span></span>
<span class="line"><span></span></span>
<span class="line"><span>允许场景:操作 A(10:00 完成) → 操作 B(10:01 完成)</span></span>
<span class="line"><span>        但全局顺序里可以是 B → A,只要每个客户端&quot;内部顺序&quot;对就行</span></span></code></pre></div><p><strong>关键性质</strong>:<strong>每个客户端看到的操作序列必须和它发出的顺序一致(program order),但客户端之间的相对顺序可以任意</strong>。</p><p><strong>典型实现</strong>:<strong>ZooKeeper 的写</strong>(ZAB 协议给 Sequential 但不是 Linearizability,因为它的快速读不走 Leader,可能读到旧 Leader 的数据)。</p><p><strong>重要细节</strong>:<strong>单 CPU 内核的指令执行就是 Sequential Consistency</strong>——这是计算机体系结构里的原始概念,<strong>1979 年 Lamport 提出</strong>,后来才被分布式系统借用。</p><h3 id="_4-3-linearizability-vs-sequential-的关键区别" tabindex="-1">4.3 Linearizability vs Sequential 的关键区别 <a class="header-anchor" href="#_4-3-linearizability-vs-sequential-的关键区别" aria-label="Permalink to &quot;4.3 Linearizability vs Sequential 的关键区别&quot;">​</a></h3><p><strong>这两个模型最容易被混淆</strong>。看这个例子:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>真实时间轴 (wall clock):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Time 1:  Client A: write(x, 1) [完成]</span></span>
<span class="line"><span>  Time 2:  Client B: read(x) → ???</span></span>
<span class="line"><span>  Time 3:  Client C: write(x, 2) [完成]</span></span>
<span class="line"><span>  Time 4:  Client D: read(x) → ???</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Linearizability:</span></span>
<span class="line"><span>  Time 2 的读必须返回 1 或 2(不能是 0)</span></span>
<span class="line"><span>  因为 A 的写在 Time 2 之前已完成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sequential Consistency:</span></span>
<span class="line"><span>  Time 2 的读可以返回 0 / 1 / 2</span></span>
<span class="line"><span>  因为不强制 real-time order</span></span>
<span class="line"><span></span></span>
<span class="line"><span>       Linearizability ⊊ Sequential ⊊ Causal ⊊ Eventual</span></span>
<span class="line"><span>       (前者比后者更强)</span></span></code></pre></div><blockquote><p><strong>Linearizability 给你&quot;分布式系统看起来像一台单机&quot;的幻觉</strong>——这是它最强的卖点,也是 etcd / ZK / TiKV 选它的原因(应用程序员可以&quot;忘记&quot;分布式)。<strong>代价是每次写都要 quorum + 同步</strong>——延迟成本不可忽视。</p></blockquote><h3 id="_4-4-causal-consistency-因果一致性" tabindex="-1">4.4 Causal Consistency(因果一致性) <a class="header-anchor" href="#_4-4-causal-consistency-因果一致性" aria-label="Permalink to &quot;4.4 Causal Consistency(因果一致性)&quot;">​</a></h3><p><strong>因果有关的操作必须按因果顺序看到</strong>,<strong>无关的可以乱序</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;因果关系&quot;的定义(Lamport happens-before):</span></span>
<span class="line"><span>  1. 同一客户端的两个操作:先发的有因果于后发的</span></span>
<span class="line"><span>  2. 一个客户端的写,另一个客户端读到了:写有因果于读</span></span>
<span class="line"><span>  3. 因果是传递的:A → B 且 B → C,则 A → C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>因果一致性保证:</span></span>
<span class="line"><span>  如果操作 X 因果先于操作 Y,那么所有节点必须先看到 X 再看到 Y</span></span>
<span class="line"><span>  没有因果关系的操作,顺序无所谓</span></span></code></pre></div><p><strong>典型用例</strong>:<strong>评论系统</strong>——评论必须在发帖之后被看到(因果),<strong>但不同帖子的评论顺序可以乱序</strong>(无关)。</p><p><strong>实现</strong>:<strong>向量时钟 / 版本向量</strong>(详见 07 篇)——Dynamo、Riak、COPS 用这个模型。</p><p><strong>为什么重要</strong>:<strong>因果一致性是 CAP 之外的甜点</strong>——可以同时满足 Available + Causal,<strong>不需要付出 Linearizability 的延迟代价</strong>(详见 18 篇)。</p><h3 id="_4-5-ryw-monotonic-reads-eventual-弱档三件套" tabindex="-1">4.5 RYW / Monotonic Reads / Eventual(弱档三件套) <a class="header-anchor" href="#_4-5-ryw-monotonic-reads-eventual-弱档三件套" aria-label="Permalink to &quot;4.5 RYW / Monotonic Reads / Eventual(弱档三件套)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>保证</th><th>典型场景</th><th>实现</th></tr></thead><tbody><tr><td>Read-Your-Writes</td><td>你自己的写,自己立刻能读到</td><td>改头像后立刻刷新看到</td><td>Session 粘滞 / 写后读主</td></tr><tr><td>Monotonic Reads</td><td>看到某版本后,不会读到更旧的</td><td>刷朋友圈不能&quot;刷新少几条&quot;</td><td>客户端带最高版本号</td></tr><tr><td>Eventual</td><td>足够时间后所有副本一致</td><td>点赞数 / 关注数</td><td>异步复制 / Gossip / CRDT</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Alice: write(x, 1) → read(x) → 必须返回 1 (RYW)</span></span>
<span class="line"><span>Bob:                  read(x) → 可能返回 0 (RYW 不要求)</span></span></code></pre></div><p>最终一致是最弱的——<strong>中间状态可能任意旧、任意乱</strong>,只承诺&quot;停止写入后,所有副本最终收敛&quot;。<strong>典型实现</strong>:异步复制(Dynamo / Cassandra)、Gossip、CRDT。</p><h3 id="_4-6-一致性模型层级图" tabindex="-1">4.6 一致性模型层级图 <a class="header-anchor" href="#_4-6-一致性模型层级图" aria-label="Permalink to &quot;4.6 一致性模型层级图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                Linearizability</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                Sequential Consistency</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                Causal Consistency</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                  ┌────┼────┐</span></span>
<span class="line"><span>                  ▼    ▼    ▼</span></span>
<span class="line"><span>              RYW   MR   MW    (Read-Your-Writes / Monotonic Reads / Monotonic Writes)</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                Eventual Consistency</span></span></code></pre></div><p><strong>向上越强、越贵;向下越弱、越快</strong>。<strong>真实工程是给每类操作选不同档</strong>——余额选 Linearizability,头像选 RYW,点赞数选 Eventual。</p><hr><h2 id="五、三者关系图" tabindex="-1">五、三者关系图 <a class="header-anchor" href="#五、三者关系图" aria-label="Permalink to &quot;五、三者关系图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>共识 (Consensus, 09-15 篇)        N 个节点决定一个值</span></span>
<span class="line"><span>   Paxos / Raft / ZAB             └─ 保证 Agreement</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ▼ 产出</span></span>
<span class="line"><span>一致性结果 (Consistency)          多副本数据相同程度</span></span>
<span class="line"><span>   强一致 / 弱一致 / 最终一致</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ▼ 决定</span></span>
<span class="line"><span>一致性模型 (Consistency Model, 16-19 篇)   程序员看到的契约</span></span>
<span class="line"><span>   Linearizability / Sequential / Causal / Eventual / RYW / Monotonic</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ▼ 给</span></span>
<span class="line"><span>应用程序员                        写业务代码假设的&quot;内存模型&quot;</span></span></code></pre></div><p><strong>记住这个图</strong>——后面 30 篇所有内容都在这三层之间穿梭:<strong>共识算法是机制,产出一致性结果,对外承诺一致性模型</strong>。</p><hr><h2 id="六、工程混淆案例-为什么-kafka-是强一致-是错的" tabindex="-1">六、工程混淆案例:为什么&quot;Kafka 是强一致&quot;是错的 <a class="header-anchor" href="#六、工程混淆案例-为什么-kafka-是强一致-是错的" aria-label="Permalink to &quot;六、工程混淆案例:为什么&quot;Kafka 是强一致&quot;是错的&quot;">​</a></h2><p>这是面试和文档里最常见的错误说法。<strong>Kafka 提供&quot;分区内顺序 + ISR 同步复制&quot;——但这不等于 Linearizability</strong>。</p><h3 id="_6-1-kafka-的承诺" tabindex="-1">6.1 Kafka 的承诺 <a class="header-anchor" href="#_6-1-kafka-的承诺" aria-label="Permalink to &quot;6.1 Kafka 的承诺&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>acks=all + min.insync.replicas=2 + replication.factor=3:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  生产者发送消息 → Leader 收到 → 复制到所有 ISR 副本 → 全部确认 → 返回 ack</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  保证 1: 同一分区内消息顺序一致(分区内顺序)</span></span>
<span class="line"><span>  保证 2: ack 返回后,消息至少在 ISR 中 2 个副本上</span></span>
<span class="line"><span>  保证 3: 主挂了,从 ISR 中选举新主,数据不丢</span></span></code></pre></div><p><strong>Kafka 的这套机制可以叫&quot;持久化保证&quot;或&quot;durability + ordering&quot;,但不是 Linearizability</strong>。</p><h3 id="_6-2-为什么不是-linearizability" tabindex="-1">6.2 为什么不是 Linearizability? <a class="header-anchor" href="#_6-2-为什么不是-linearizability" aria-label="Permalink to &quot;6.2 为什么不是 Linearizability?&quot;">​</a></h3><p><strong>关键反例</strong>:<strong>消费者看到的顺序可能和生产者真实写入的实时顺序不一致</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer A → Partition 0: msg1</span></span>
<span class="line"><span>Producer B → Partition 1: msg2 (真实时间晚于 msg1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Consumer 同时订阅两个分区:可能先消费到 msg2 再消费到 msg1</span></span>
<span class="line"><span>→ 违反 Linearizability 的 real-time order</span></span>
<span class="line"><span>→ Kafka 仅保证&quot;分区内顺序&quot;——比 Sequential 还弱</span></span></code></pre></div><h3 id="_6-3-其他常见混淆" tabindex="-1">6.3 其他常见混淆 <a class="header-anchor" href="#_6-3-其他常见混淆" aria-label="Permalink to &quot;6.3 其他常见混淆&quot;">​</a></h3><table tabindex="0"><thead><tr><th>系统</th><th>错误说法</th><th>正确说法</th></tr></thead><tbody><tr><td>Kafka</td><td>强一致</td><td>分区内有序 + ISR 持久化(非 Linearizability)</td></tr><tr><td>Redis 主从</td><td>强一致</td><td>异步复制,Eventual</td></tr><tr><td>MySQL 半同步</td><td>Linearizability</td><td>同步复制达到 RYW + Monotonic</td></tr><tr><td>ZooKeeper</td><td>Linearizability</td><td><strong>写 Linearizability,默认读 Sequential</strong>(读不走 Leader)</td></tr><tr><td>etcd</td><td>强一致</td><td>Linearizability(读默认走 Leader 或 ReadIndex)</td></tr><tr><td>Cassandra</td><td>最终一致</td><td><strong>可调,默认 Eventual,Quorum 可达 RYW</strong></td></tr></tbody></table><blockquote><p><strong>看一个系统的文档,要看它对每类操作分别承诺什么模型</strong>——一刀切地说&quot;强一致&quot;或&quot;最终一致&quot;,<strong>99% 的概率是说错了</strong>。</p></blockquote><hr><h2 id="七、单机内存模型-一致性模型的-原型" tabindex="-1">七、单机内存模型:一致性模型的&quot;原型&quot; <a class="header-anchor" href="#七、单机内存模型-一致性模型的-原型" aria-label="Permalink to &quot;七、单机内存模型:一致性模型的&quot;原型&quot;&quot;">​</a></h2><p>很多人不知道的事:<strong>Linearizability、Sequential Consistency 这些词最早是单机多核 CPU 的内存模型</strong>——<strong>1979 年 Lamport 在 <em>How to Make a Multiprocessor Computer...</em> 提出 Sequential Consistency,后来才被分布式系统借用</strong>。</p><h3 id="_7-1-多核-cpu-微缩分布式系统" tabindex="-1">7.1 多核 CPU = 微缩分布式系统 <a class="header-anchor" href="#_7-1-多核-cpu-微缩分布式系统" aria-label="Permalink to &quot;7.1 多核 CPU = 微缩分布式系统&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    内存 (x=0)</span></span>
<span class="line"><span>                   /         \\</span></span>
<span class="line"><span>              CPU 1 缓存    CPU 2 缓存</span></span>
<span class="line"><span>              (x=0)         (x=0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CPU 1: x = 1 (写自己缓存) → CPU 2 还看到 x = 0</span></span>
<span class="line"><span>→ 多核 CPU 也有&quot;分布式数据一致性&quot;问题</span></span>
<span class="line"><span>→ 解决:MESI 协议 + Memory Barrier</span></span></code></pre></div><p>多核 CPU 的&quot;多副本(L1/L2/L3 缓存)、消息传递(总线协议)、并发访问&quot;——<strong>就是一个微缩的分布式系统</strong>。所有分布式一致性模型的概念,在单机内存层都已经被反复推过一遍。</p><h3 id="_7-2-x86-tso-vs-arm-relaxed" tabindex="-1">7.2 x86 TSO vs ARM Relaxed <a class="header-anchor" href="#_7-2-x86-tso-vs-arm-relaxed" aria-label="Permalink to &quot;7.2 x86 TSO vs ARM Relaxed&quot;">​</a></h3><p><strong>x86 TSO(Total Store Order)</strong>——比 Sequential 弱一点,<strong>允许 Store→Load 重排</strong>(Store Buffer 吸收 Store,Load 直接读 Cache):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>程序顺序:store A=1; load B</span></span>
<span class="line"><span>可能执行:load B; store A=1   ← x86 允许</span></span>
<span class="line"><span>→ Peterson 算法在 x86 上需要 mfence 指令</span></span></code></pre></div><p><strong>ARM Relaxed</strong>——比 x86 更弱,<strong>几乎所有顺序都可以重排</strong>,除非显式 <code>dmb</code> / <code>ldar</code> / <code>stlr</code> 屏障。<strong>这就是用 C++ 写跨平台多线程要用 <code>std::atomic</code> + memory order 的原因</strong>。</p><h3 id="_7-3-单机模型和分布式模型的对应" tabindex="-1">7.3 单机模型和分布式模型的对应 <a class="header-anchor" href="#_7-3-单机模型和分布式模型的对应" aria-label="Permalink to &quot;7.3 单机模型和分布式模型的对应&quot;">​</a></h3><table tabindex="0"><thead><tr><th>单机内存模型</th><th>分布式一致性模型</th></tr></thead><tbody><tr><td>Sequential Consistency</td><td>Sequential Consistency</td></tr><tr><td>x86 TSO</td><td>接近 Linearizability(差 store-load reorder)</td></tr><tr><td>ARM Relaxed</td><td>Causal 甚至更弱</td></tr><tr><td>Memory Barrier</td><td>Synchronous Replication / Read Barrier</td></tr><tr><td>MESI 缓存协议</td><td>主从复制 / Quorum 复制</td></tr><tr><td>CPU Cache / Cache Line</td><td>副本 / 数据条目</td></tr></tbody></table><blockquote><p><strong>你写 Java <code>volatile</code>、C++ <code>std::atomic</code> 的内存序参数,本质就是在选择&quot;一致性模型&quot;</strong>——只是范围在单机。<strong>理解了单机内存模型,分布式一致性模型就只是&quot;把单机概念放大到集群&quot;</strong>。Herlihy &amp; Wing 1990 的 Linearizability 论文里<strong>完全不区分&quot;单机多核&quot;和&quot;分布式&quot;</strong>——同一套理论。</p></blockquote><hr><h2 id="八、为什么这套术语混乱这么久" tabindex="-1">八、为什么这套术语混乱这么久 <a class="header-anchor" href="#八、为什么这套术语混乱这么久" aria-label="Permalink to &quot;八、为什么这套术语混乱这么久&quot;">​</a></h2><ol><li><strong>中文翻译都叫&quot;一致&quot;</strong>——Consistency / Consensus / Consistency Model 都翻&quot;一致性&quot;或&quot;共识/一致性&quot;,<strong>中文读者入门就分不清</strong></li><li><strong>早期论文不严格</strong>——1970-1980 年代概念在演化,<strong>很多文章用语不严谨</strong></li><li><strong>工程文档为了简单</strong>——&quot;我们提供强一致&quot;听起来比&quot;我们提供 Linearizability 写 + Sequential 读&quot;清楚,<strong>但牺牲了精确性</strong></li><li><strong>CAP 定理的传播</strong>——Brewer 的 CAP 里 C 是 Linearizability,<strong>但后来被讲成 ACID 的 C,再被讲成&quot;多副本一致&quot;</strong>,<strong>层层走样</strong></li><li><strong>面试题文化</strong>——简化成&quot;三选二&quot;、&quot;BASE&quot;,<strong>牺牲精确换记忆性</strong></li></ol><p><strong>这个系列后续 30 篇,术语会严格区分</strong>:<strong>Consensus 永远指算法,Consistency Model 永远指契约</strong>,<strong>避免笼统说&quot;一致性&quot;</strong>。</p><hr><h2 id="九、读完这一篇后该有的认知" tabindex="-1">九、读完这一篇后该有的认知 <a class="header-anchor" href="#九、读完这一篇后该有的认知" aria-label="Permalink to &quot;九、读完这一篇后该有的认知&quot;">​</a></h2><ol><li><strong>共识、一致性、一致性模型是三个完全不同的概念</strong>——前者是算法,中者是工程结果,后者是程序员契约</li><li><strong>共识算法(Paxos / Raft)产出一致性结果,对外承诺一致性模型</strong>——这条因果链是分布式系统的骨架</li><li><strong>&quot;强一致&quot;是不严谨的工程口语,真正要看的是 Linearizability、Sequential、Causal、Eventual 这些精确模型</strong></li><li><strong>Linearizability ≠ Sequential ≠ Causal</strong>——三者之间差着具体的、可形式化的不变量,<strong>选错档位系统就崩</strong></li><li><strong>Kafka / ZK / etcd 提供的一致性模型不同</strong>——别凭印象选,看官方文档对每个操作的精确承诺</li><li><strong>单机内存模型和分布式一致性模型是同一套理论</strong>——<code>std::atomic</code>、<code>volatile</code> 就是单机的&quot;一致性模型选择&quot;</li></ol><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>混着用三个术语</strong>——文档 / 简历 / 面试<strong>严格区分</strong>,&quot;我们用 Paxos 实现共识,提供 Linearizability 模型&quot;才是精确表达</li><li><strong>以为 Kafka 是强一致</strong>——它只是分区内有序 + 持久化,<strong>不是 Linearizability</strong>,<strong>跨分区无序</strong></li><li><strong>以为 ZooKeeper 全 Linearizability</strong>——<strong>写是 Linearizability,默认读是 Sequential</strong>(不走 Leader,可能读旧值),要 Linearizability 读必须 sync() 后再读</li><li><strong>以为 Redis 主从是强一致</strong>——异步复制,<strong>主挂数据可能丢</strong>,Eventual 都谈不上</li><li><strong>以为最终一致 = 不一致</strong>——最终一致有收敛窗口,<strong>通常 100 ms - 几秒,99% 用户感知不到</strong></li><li><strong>以为 Sequential 比 Linearizability 慢&quot;一点&quot;</strong>——不,<strong>两者实现差异巨大</strong>:Linearizability 需要严格全局顺序,Sequential 允许 reorder</li><li><strong>把 ACID 的 C 等同于 CAP 的 C</strong>——<strong>完全不同</strong>!ACID 的 C 是业务约束,CAP 的 C 是 Linearizability</li><li><strong>写业务代码不思考一致性模型</strong>——所有&quot;分布式 bug&quot;几乎都源自&quot;程序员假设的模型 &gt; 系统实际提供的模型&quot;</li><li><strong>不区分共识和复制</strong>——MySQL 主从是复制不是共识,<strong>主挂了不能自动选主,数据可能丢</strong></li><li><strong>用&quot;我们用 Raft 所以一定强一致&quot;作为终点</strong>——Raft 给写 Linearizability,<strong>默认读可能拿旧值</strong>,要严格 Linearizability 读必须 ReadIndex / Lease Read</li></ol><hr><h2 id="第一层小结" tabindex="-1">第一层小结 <a class="header-anchor" href="#第一层小结" aria-label="Permalink to &quot;第一层小结&quot;">​</a></h2><p>01-03 这三篇是<strong>心智层</strong>的核心装备:</p><ul><li><strong>01 分布式系统总览</strong>:为什么要上分布式 / 五座大山 / 系列地图</li><li><strong>02 八大谬误与故障模型</strong>:网络不可靠的 8 个具体形态 / Crash-recovery vs Byzantine / 时间模型</li><li><strong>03 一致性、共识、一致性模型</strong>:三个最容易混的术语,讲清楚再读论文</li></ul><p><strong>这三篇是后续 27 篇的&quot;词汇表&quot;</strong>——下面读 CAP / FLP / Paxos / Raft / Spanner,<strong>任何论文 / 文档里出现的词都能精准对位</strong>,<strong>不会再被&quot;强一致&quot;、&quot;共识&quot;、&quot;一致&quot;绕晕</strong>。</p><hr><p>下一篇:<code>04-CAP、PACELC、BASE.md</code>。CAP 是被讲烂的定理,<strong>99% 的人背得出&quot;三选二&quot;但都答错了&quot;二选什么&quot;</strong>——这一篇结合 03 篇的精确术语重新讲一遍 CAP:<strong>它的 C 是 Linearizability,P 不是选项是物理事实,真正的选择只在分区时</strong>。然后引出 PACELC——CAP 没说清楚的&quot;正常情况下也有的延迟-一致性 trade-off&quot;,和 BASE——互联网公司实战的&quot;基本可用 + 软状态 + 最终一致&quot;。<strong>04 篇结束后,心智层完成,我们就要进入时间和因果(05-08 篇)的深水区</strong>。</p>`,124)])])}const h=n(o,[["render",i]]);export{g as __pageData,h as default};
